#[no_mangle]
pub extern "C" fn rust_main(cpu_id: usize, firmware_arg: usize) -> ! {
    unsafe {
        mm::zero_bss();
    }

    if cpu_id != 0 {
        arch::park();
    }

    console::init();
    println!("OSoldierBoy kernel");
    println!("cpu={} firmware_arg=0x{:x}", cpu_id, firmware_arg);
    mm::init();
    contest::run();
    println!("system halt");
    arch::shutdown()
}

use core::panic::PanicInfo;

use crate::println;

#[panic_handler]
fn panic(info: &PanicInfo<'_>) -> ! {
    println!("kernel panic: {}", info);
    crate::arch::shutdown()
}

use core::fmt::{self, Write};

pub fn init() {
    crate::arch::console_init();
}

pub fn write_bytes(bytes: &[u8]) {
    for &byte in bytes {
        if byte == b'\n' {
            crate::arch::putchar(b'\r');
        }
        crate::arch::putchar(byte);
    }
}

pub fn write_fmt(args: fmt::Arguments<'_>) {
    let _ = Console.write_fmt(args);
}

struct Console;

impl Write for Console {
    fn write_str(&mut self, text: &str) -> fmt::Result {
        write_bytes(text.as_bytes());
        Ok(())
    }
}

#[macro_export]
macro_rules! print {
    ($($arg:tt)*) => {{
        $crate::console::write_fmt(format_args!($($arg)*));
    }};
}

#[macro_export]
macro_rules! println {
    () => {
        $crate::print!("\n")
    };
    ($fmt:expr) => {
        $crate::print!(concat!($fmt, "\n"))
    };
    ($fmt:expr, $($arg:tt)*) => {
        $crate::print!(concat!($fmt, "\n"), $($arg)*)
    };
}

const SEARCH_ROOTS: [&str; 3] = ["/", "/musl", "/glibc"];
const TEST_SUFFIX: &str = "_testcode.sh";

use crate::println;

pub struct ScriptPlan {
    roots: &'static [&'static str],
    suffix: &'static str,
}

impl ScriptPlan {
    pub const fn oscomp() -> Self {
        Self {
            roots: &SEARCH_ROOTS,
            suffix: TEST_SUFFIX,
        }
    }

    pub fn describe(&self) {
        println!("contest runner");
        println!("script suffix: {}", self.suffix);
        for root in self.roots {
            println!("scan root: {}", root);
        }
    }

    pub const fn roots(&self) -> &'static [&'static str] {
        self.roots
    }
}

pub fn run() {
    ScriptPlan::oscomp().describe();
    crate::drivers::block::smoke_test();
    println!("block/ext4/user-mode execution is the next implementation stage");
}

#[allow(dead_code)]
pub fn is_test_script(path: &str) -> bool {
    path.ends_with(TEST_SUFFIX)
}

