use core::arch::{asm, global_asm};

global_asm!(include_str!("riscv64.S"));

pub const PAGE_SIZE: usize = 4096;
pub const PHYS_MEMORY_BASE: usize = 0x8000_0000;
pub const PHYS_MEMORY_SIZE: usize = 128 * 1024 * 1024;
pub const KERNEL_BASE: usize = 0x8020_0000;
const TIMEBASE_HZ: u64 = 10_000_000;
const SBI_EXT_TIME: usize = 0x5449_4d45;
const SBI_EXT_TIME_SET_TIMER: usize = 0;
const SBI_LEGACY_SET_TIMER: usize = 0;

const UART_BASE: usize = 0x1000_0000;
const UART_RHR_THR: usize = 0;
const UART_IER: usize = 1;
const UART_FCR: usize = 2;
const UART_LCR: usize = 3;
const UART_LSR: usize = 5;
const UART_LSR_THRE: u8 = 1 << 5;

pub fn console_init() {
    unsafe {
        write_reg(UART_IER, 0x00);
        write_reg(UART_LCR, 0x80);
        write_reg(UART_RHR_THR, 0x03);
        write_reg(UART_IER, 0x00);
        write_reg(UART_LCR, 0x03);
        write_reg(UART_FCR, 0x07);
    }
}

pub fn putchar(byte: u8) {
    unsafe {
        while read_reg(UART_LSR) & UART_LSR_THRE == 0 {}
        write_reg(UART_RHR_THR, byte);
    }
}

pub fn shutdown() -> ! {
    unsafe {
        let _ = sbi_call(0x5352_5354, 0, 0, 0, 0);
        let _ = sbi_call(0x08, 0, 0, 0, 0);
    }
    park()
}

pub fn park() -> ! {
    loop {
        unsafe {
            asm!("wfi", options(nomem, nostack));
        }
    }
}

pub fn monotonic_time_us() -> u64 {
    read_time_ticks().saturating_mul(1_000_000) / TIMEBASE_HZ
}

pub fn read_time_ticks() -> u64 {
    let ticks: u64;
    unsafe {
        asm!("rdtime {}", out(reg) ticks, options(nomem, nostack, preserves_flags));
    }
    ticks
}

pub fn set_timer_after_us(delta_us: u64) {
    let delta_ticks = delta_us.saturating_mul(TIMEBASE_HZ) / 1_000_000;
    set_timer_ticks(read_time_ticks().saturating_add(delta_ticks.max(1)));
}

pub fn set_timer_ticks(ticks: u64) {
    unsafe {
        let error = sbi_call(SBI_EXT_TIME, SBI_EXT_TIME_SET_TIMER, ticks as usize, 0, 0);
        if error != 0 {
            let _ = sbi_call(SBI_LEGACY_SET_TIMER, 0, ticks as usize, 0, 0);
        }
    }
}

pub const fn virt_to_phys(addr: usize) -> usize {
    addr
}

pub const fn phys_to_virt(addr: usize) -> usize {
    addr
}

unsafe fn read_reg(offset: usize) -> u8 {
    core::ptr::read_volatile((UART_BASE + offset) as *const u8)
}

unsafe fn write_reg(offset: usize, value: u8) {
    core::ptr::write_volatile((UART_BASE + offset) as *mut u8, value);
}

unsafe fn sbi_call(eid: usize, fid: usize, arg0: usize, arg1: usize, arg2: usize) -> usize {
    let mut ret = arg0;
    asm!(
        "ecall",
        inlateout("a0") ret,
        in("a1") arg1,
        in("a2") arg2,
        in("a6") fid,
        in("a7") eid,
        options(nostack)
    );
    ret
}

use core::arch::global_asm;

global_asm!(include_str!("loongarch64.S"));

pub const PAGE_SIZE: usize = 4096;
pub const PHYS_MEMORY_BASE: usize = 0x9000_0000;
pub const PHYS_MEMORY_SIZE: usize = 128 * 1024 * 1024;
pub const KERNEL_BASE_PADDR: usize = 0x9000_0000;
pub const KERNEL_BASE_VADDR: usize = 0x9000_0000_9000_0000;
pub const PHYS_VIRT_OFFSET: usize = KERNEL_BASE_VADDR - KERNEL_BASE_PADDR;

const UART_BASE: usize = 0x1fe0_01e0;
const UART_RHR_THR: usize = 0;
const UART_IER: usize = 1;
const UART_FCR: usize = 2;
const UART_LCR: usize = 3;
const GED_ADDR: usize = 0x100e_001c;

pub fn console_init() {
    unsafe {
        write_reg(UART_IER, 0x00);
        write_reg(UART_LCR, 0x80);
        write_reg(UART_RHR_THR, 0x03);
        write_reg(UART_IER, 0x00);
        write_reg(UART_LCR, 0x03);
        write_reg(UART_FCR, 0x07);
    }
}

pub fn putchar(byte: u8) {
    unsafe {
        write_reg(UART_RHR_THR, byte);
    }
}

pub fn shutdown() -> ! {
    unsafe {
        core::ptr::write_volatile(GED_ADDR as *mut u8, 0x34);
    }
    park()
}

pub fn park() -> ! {
    loop {
        core::hint::spin_loop();
    }
}

pub const fn monotonic_time_us() -> u64 {
    1_000_000
}

pub const fn virt_to_phys(addr: usize) -> usize {
    if addr >= KERNEL_BASE_VADDR {
        addr - PHYS_VIRT_OFFSET
    } else {
        addr
    }
}

pub const fn phys_to_virt(addr: usize) -> usize {
    if addr >= PHYS_MEMORY_BASE {
        addr + PHYS_VIRT_OFFSET
    } else {
        addr
    }
}

unsafe fn write_reg(offset: usize, value: u8) {
    core::ptr::write_volatile((UART_BASE + offset) as *mut u8, value);
}

