use crate::{arch, println};

pub const PAGE_SIZE: usize = arch::PAGE_SIZE;

unsafe extern "C" {
    static mut __bss_start: u8;
    static mut __bss_end: u8;
    static __kernel_start: u8;
    static __kernel_end: u8;
}

pub unsafe fn zero_bss() {
    let mut current = core::ptr::addr_of_mut!(__bss_start);
    let end = core::ptr::addr_of_mut!(__bss_end);

    while current < end {
        core::ptr::write_volatile(current, 0);
        current = current.add(1);
    }
}

pub fn init() {
    heap::init();

    let kernel_start = symbol_addr(core::ptr::addr_of!(__kernel_start));
    let kernel_end = symbol_addr(core::ptr::addr_of!(__kernel_end));
    let frame_start = align_up(arch::virt_to_phys(kernel_end), PAGE_SIZE);
    let frame_end = arch::PHYS_MEMORY_BASE + arch::PHYS_MEMORY_SIZE;

    frame::init(frame_start, frame_end);

    println!(
        "mm: kernel=[0x{:x}, 0x{:x}) free-frames=[0x{:x}, 0x{:x})",
        kernel_start, kernel_end, frame_start, frame_end
    );

    heap::smoke_test();
    frame::smoke_test();
    paging::smoke_test();
    user::smoke_test();
}

pub const fn align_up(value: usize, align: usize) -> usize {
    (value + align - 1) & !(align - 1)
}

pub const fn align_down(value: usize, align: usize) -> usize {
    value & !(align - 1)
}

fn symbol_addr(symbol: *const u8) -> usize {
    symbol as usize
}

use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

use crate::{
    mm::{align_down, align_up, PAGE_SIZE},
    println,
};

static FRAME_ALLOCATOR: FrameAllocator = FrameAllocator::new();
const MAX_FREE_FRAMES: usize = 32768;
static mut FREE_FRAMES: [usize; MAX_FREE_FRAMES] = [0; MAX_FREE_FRAMES];

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct PhysFrame {
    start: usize,
}

impl PhysFrame {
    pub const fn new(start: usize) -> Self {
        Self { start }
    }

    pub const fn start(self) -> usize {
        self.start
    }
}

pub fn init(phys_start: usize, phys_end: usize) {
    FRAME_ALLOCATOR.init(phys_start, phys_end);
    println!(
        "frame: allocator range=[0x{:x}, 0x{:x}) total={} pages",
        FRAME_ALLOCATOR.next(),
        FRAME_ALLOCATOR.end(),
        FRAME_ALLOCATOR.free_frames()
    );
}

pub fn alloc() -> Option<PhysFrame> {
    FRAME_ALLOCATOR.alloc()
}

pub fn dealloc(frame: PhysFrame) {
    FRAME_ALLOCATOR.dealloc(frame);
}

pub fn smoke_test() {
    let first = alloc().expect("first frame allocation failed");
    let second = alloc().expect("second frame allocation failed");

    println!(
        "frame: smoke ok first=0x{:x} second=0x{:x} remaining={} pages",
        first.start(),
        second.start(),
        FRAME_ALLOCATOR.free_frames()
    );
    dealloc(second);
    dealloc(first);
}

struct FrameAllocator {
    locked: AtomicBool,
    start: AtomicUsize,
    next: AtomicUsize,
    end: AtomicUsize,
    free_count: AtomicUsize,
}

impl FrameAllocator {
    pub const fn new() -> Self {
        Self {
            locked: AtomicBool::new(false),
            start: AtomicUsize::new(0),
            next: AtomicUsize::new(0),
            end: AtomicUsize::new(0),
            free_count: AtomicUsize::new(0),
        }
    }

    pub fn init(&self, phys_start: usize, phys_end: usize) {
        self.lock();
        let start = align_up(phys_start, PAGE_SIZE);
        self.start.store(start, Ordering::Relaxed);
        self.next.store(start, Ordering::Relaxed);
        self.end
            .store(align_down(phys_end, PAGE_SIZE), Ordering::Relaxed);
        self.free_count.store(0, Ordering::Relaxed);
        self.unlock();
    }

    pub fn alloc(&self) -> Option<PhysFrame> {
        self.lock();

        let free_count = self.free_count.load(Ordering::Relaxed);
        let result = if free_count != 0 {
            let next_count = free_count - 1;
            self.free_count.store(next_count, Ordering::Relaxed);
            let start = unsafe { FREE_FRAMES[next_count] };
            Some(PhysFrame::new(start))
        } else {
            let next = self.next.load(Ordering::Relaxed);
            let new_next = next.checked_add(PAGE_SIZE);
            match new_next {
                Some(value) if value <= self.end.load(Ordering::Relaxed) => {
                    self.next.store(value, Ordering::Relaxed);
                    Some(PhysFrame::new(next))
                }
                _ => None,
            }
        };

        self.unlock();
        result
    }

    pub fn dealloc(&self, frame: PhysFrame) {
        let start = frame.start();
        if start % PAGE_SIZE != 0 {
            return;
        }
        if start < self.start.load(Ordering::Relaxed) || start >= self.end.load(Ordering::Relaxed) {
            return;
        }

        self.lock();
        let free_count = self.free_count.load(Ordering::Relaxed);
        if free_count < MAX_FREE_FRAMES {
            unsafe {
                FREE_FRAMES[free_count] = start;
            }
            self.free_count.store(free_count + 1, Ordering::Relaxed);
        }
        self.unlock();
    }

    pub fn free_frames(&self) -> usize {
        let next = self.next.load(Ordering::Relaxed);
        let end = self.end.load(Ordering::Relaxed);
        end.saturating_sub(next) / PAGE_SIZE + self.free_count.load(Ordering::Relaxed)
    }

    pub fn next(&self) -> usize {
        self.next.load(Ordering::Relaxed)
    }

    pub fn end(&self) -> usize {
        self.end.load(Ordering::Relaxed)
    }

    fn lock(&self) {
        while self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            core::hint::spin_loop();
        }
    }

    fn unlock(&self) {
        self.locked.store(false, Ordering::Release);
    }
}

use alloc::{boxed::Box, vec::Vec};
use core::alloc::{GlobalAlloc, Layout};
use core::ptr::null_mut;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

use crate::{mm::align_up, println};

const KERNEL_HEAP_SIZE: usize = 64 * 1024 * 1024;
const MAX_FREE_BLOCKS: usize = 8192;

#[repr(align(4096))]
struct KernelHeap {
    bytes: [u8; KERNEL_HEAP_SIZE],
}

static mut KERNEL_HEAP: KernelHeap = KernelHeap {
    bytes: [0; KERNEL_HEAP_SIZE],
};

#[derive(Clone, Copy)]
struct FreeBlock {
    ptr: usize,
    size: usize,
}

static mut FREE_BLOCKS: [FreeBlock; MAX_FREE_BLOCKS] =
    [FreeBlock { ptr: 0, size: 0 }; MAX_FREE_BLOCKS];

#[global_allocator]
static ALLOCATOR: BumpAllocator = BumpAllocator::new();

pub fn init() {
    let start = unsafe { core::ptr::addr_of_mut!(KERNEL_HEAP.bytes) as *mut u8 as usize };
    ALLOCATOR.init(start, KERNEL_HEAP_SIZE);
    println!(
        "heap: bump allocator range=[0x{:x}, 0x{:x})",
        start,
        start + KERNEL_HEAP_SIZE
    );
}

pub fn smoke_test() {
    let boxed = Box::new(0x4f53_424f_5955_0001usize);
    let mut values = Vec::new();
    values.push(1usize);
    values.push(2);
    values.push(3);
    println!(
        "heap: smoke ok box=0x{:x} vec_len={} vec_sum={}",
        *boxed,
        values.len(),
        values.iter().copied().sum::<usize>()
    );
}

struct BumpAllocator {
    locked: AtomicBool,
    start: AtomicUsize,
    end: AtomicUsize,
    next: AtomicUsize,
    free_count: AtomicUsize,
    initialized: AtomicBool,
}

impl BumpAllocator {
    pub const fn new() -> Self {
        Self {
            locked: AtomicBool::new(false),
            start: AtomicUsize::new(0),
            end: AtomicUsize::new(0),
            next: AtomicUsize::new(0),
            free_count: AtomicUsize::new(0),
            initialized: AtomicBool::new(false),
        }
    }

    pub fn init(&self, start: usize, size: usize) {
        self.lock();
        self.start.store(start, Ordering::Relaxed);
        self.end.store(start + size, Ordering::Relaxed);
        self.next.store(start, Ordering::Relaxed);
        self.free_count.store(0, Ordering::Relaxed);
        self.initialized.store(true, Ordering::Release);
        self.unlock();
    }

    fn lock(&self) {
        while self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            core::hint::spin_loop();
        }
    }

    fn unlock(&self) {
        self.locked.store(false, Ordering::Release);
    }

    fn take_free_block(&self, size: usize, align: usize) -> Option<usize> {
        let mut index = 0usize;
        let mut count = self.free_count.load(Ordering::Relaxed);

        while index < count {
            let block = unsafe { FREE_BLOCKS[index] };
            let alloc_start = align_up(block.ptr, align);
            let block_end = block.ptr.checked_add(block.size)?;
            let alloc_end = alloc_start.checked_add(size)?;
            if alloc_end > block_end {
                index += 1;
                continue;
            }

            let prefix_size = alloc_start - block.ptr;
            let suffix_size = block_end - alloc_end;
            match (prefix_size, suffix_size) {
                (0, 0) => {
                    count -= 1;
                    unsafe {
                        FREE_BLOCKS[index] = FREE_BLOCKS[count];
                    }
                    self.free_count.store(count, Ordering::Relaxed);
                }
                (0, suffix) => unsafe {
                    FREE_BLOCKS[index] = FreeBlock {
                        ptr: alloc_end,
                        size: suffix,
                    };
                },
                (prefix, 0) => unsafe {
                    FREE_BLOCKS[index] = FreeBlock {
                        ptr: block.ptr,
                        size: prefix,
                    };
                },
                (prefix, suffix) => unsafe {
                    FREE_BLOCKS[index] = FreeBlock {
                        ptr: block.ptr,
                        size: prefix,
                    };
                    if count < MAX_FREE_BLOCKS {
                        FREE_BLOCKS[count] = FreeBlock {
                            ptr: alloc_end,
                            size: suffix,
                        };
                        self.free_count.store(count + 1, Ordering::Relaxed);
                    }
                },
            }
            return Some(alloc_start);
        }

        None
    }

    fn add_free_block(&self, ptr: usize, size: usize) {
        let Some(end) = ptr.checked_add(size) else {
            return;
        };
        let mut start = ptr;
        let mut end = end;

        loop {
            let mut merged = false;
            let mut count = self.free_count.load(Ordering::Relaxed);
            let mut index = 0usize;
            while index < count {
                let block = unsafe { FREE_BLOCKS[index] };
                let Some(block_end) = block.ptr.checked_add(block.size) else {
                    self.remove_free_block(index);
                    merged = true;
                    break;
                };
                if block_end == start {
                    start = block.ptr;
                    self.remove_free_block(index);
                    merged = true;
                    break;
                }
                if end == block.ptr {
                    end = block_end;
                    self.remove_free_block(index);
                    merged = true;
                    break;
                }
                index += 1;
                count = self.free_count.load(Ordering::Relaxed);
            }
            if !merged {
                break;
            }
        }

        let count = self.free_count.load(Ordering::Relaxed);
        if count < MAX_FREE_BLOCKS {
            unsafe {
                FREE_BLOCKS[count] = FreeBlock {
                    ptr: start,
                    size: end - start,
                };
            }
            self.free_count.store(count + 1, Ordering::Relaxed);
        }
    }

    fn remove_free_block(&self, index: usize) {
        let count = self.free_count.load(Ordering::Relaxed);
        if index >= count {
            return;
        }
        let next_count = count - 1;
        unsafe {
            FREE_BLOCKS[index] = FREE_BLOCKS[next_count];
        }
        self.free_count.store(next_count, Ordering::Relaxed);
    }
}

unsafe impl Sync for BumpAllocator {}

unsafe impl GlobalAlloc for BumpAllocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        if !self.initialized.load(Ordering::Acquire) {
            return null_mut();
        }

        self.lock();

        let size = layout.size().max(1);
