struct PageTableEntry(u64);

impl PageTableEntry {
    pub const fn empty() -> Self {
        Self(0)
    }

    pub const fn is_valid(self) -> bool {
        self.0 & PTE_V != 0
    }

    pub const fn is_leaf(self) -> bool {
        self.0 & (PTE_R | PTE_W | PTE_X) != 0
    }

    pub fn set_table(&mut self, phys: usize) {
        self.0 = (((phys as u64) >> 12) << PPN_SHIFT) | PTE_V;
    }

    pub fn set_leaf(&mut self, phys: usize, flags: MapFlags) {
        self.0 = (((phys as u64) >> 12) << PPN_SHIFT) | flags.bits() | PTE_V | PTE_A | PTE_D;
    }

    pub fn set_leaf_flags(&mut self, flags: MapFlags) {
        self.0 = (self.0 & !PTE_LEAF_FLAGS) | flags.bits() | PTE_A | PTE_D;
    }

    pub fn clear(&mut self) {
        self.0 = 0;
    }

    pub fn table_ptr(self) -> *mut PageTableNode {
        arch::phys_to_virt(self.phys_addr()) as *mut PageTableNode
    }

    pub fn phys_addr(self) -> usize {
        ((self.0 >> PPN_SHIFT) << 12) as usize
    }
}

