                    segment.phdr_index,
                    segment.offset,
                    segment.vaddr,
                    segment.filesz,
                    segment.memsz,
                    segment.flags,
                    segment.map_start,
                    segment.map_end
                );
            }
            println!("elf: {} load_segments={}", path, plan.count);
