#[derive(Clone, Copy)]
pub struct ElfImage {
    file_type: u16,
    entry: u64,
    phoff: u64,
    phentsize: u16,
    phnum: u16,
    machine: u16,
}

impl ElfImage {
    pub const fn is_position_independent(&self) -> bool {
        self.file_type == ET_DYN
    }

    pub const fn entry(&self) -> u64 {
        self.entry
    }

    pub const fn phoff(&self) -> u64 {
        self.phoff
    }

    pub const fn phentsize(&self) -> u16 {
        self.phentsize
    }

    pub const fn phnum(&self) -> u16 {
        self.phnum
    }

    pub fn parse(bytes: &[u8]) -> Result<Self, Error> {
        if bytes.len() < 64 {
            return Err(Error::TooSmall);
        }
        if &bytes[0..4] != ELF_MAGIC {
            return Err(Error::BadMagic);
        }
        if bytes[4] != ELF_CLASS_64 {
            return Err(Error::UnsupportedClass);
        }
        if bytes[5] != ELF_DATA_LSB {
            return Err(Error::UnsupportedEndian);
        }

        let machine = le_u16(bytes, 18)?;
        let phentsize = le_u16(bytes, 54)?;
        let phnum = le_u16(bytes, 56)?;
        let image = Self {
            file_type: le_u16(bytes, 16)?,
            entry: le_u64(bytes, 24)?,
            phoff: le_u64(bytes, 32)?,
            phentsize,
            phnum,
            machine,
        };

        if machine != ELF_MACHINE_RISCV {
            return Err(Error::UnsupportedMachine);
        }
        if phentsize < 56 {
            return Err(Error::BadProgramHeaderSize);
        }

        image.program_table_range(bytes)?;
        Ok(image)
    }

    pub fn program_header(&self, bytes: &[u8], index: usize) -> Result<ProgramHeader, Error> {
        if index >= self.phnum as usize {
            return Err(Error::ProgramHeaderOutOfRange);
        }
        let offset = self
            .phoff
            .checked_add(index as u64 * self.phentsize as u64)
            .ok_or(Error::OffsetOverflow)? as usize;
        let end = offset
            .checked_add(self.phentsize as usize)
            .ok_or(Error::OffsetOverflow)?;
        if end > bytes.len() {
            return Err(Error::ProgramHeaderOutOfRange);
        }

        Ok(ProgramHeader {
            header_type: le_u32(bytes, offset)?,
            flags: le_u32(bytes, offset + 4)?,
            offset: le_u64(bytes, offset + 8)?,
            vaddr: le_u64(bytes, offset + 16)?,
            paddr: le_u64(bytes, offset + 24)?,
            filesz: le_u64(bytes, offset + 32)?,
            memsz: le_u64(bytes, offset + 40)?,
            align: le_u64(bytes, offset + 48)?,
        })
    }

    pub fn load_plan(&self, bytes: &[u8]) -> Result<LoadPlan, Error> {
        let mut plan = LoadPlan::new();

        for index in 0..self.phnum as usize {
            let header = self.program_header(bytes, index)?;
            if header.header_type != PT_LOAD {
                continue;
            }
            if header.memsz < header.filesz {
                return Err(Error::BadLoadSegment);
            }
            let file_end = header
                .offset
                .checked_add(header.filesz)
                .ok_or(Error::OffsetOverflow)? as usize;
            if file_end > bytes.len() {
                return Err(Error::LoadSegmentOutOfRange);
            }

            plan.push(LoadSegment::from_header(index, header)?)?;
        }

        if plan.count == 0 {
            return Err(Error::NoLoadSegments);
        }

        Ok(plan)
    }

    pub fn interpreter<'a>(&self, bytes: &'a [u8]) -> Result<Option<&'a str>, Error> {
        for index in 0..self.phnum as usize {
            let header = self.program_header(bytes, index)?;
            if header.header_type != PT_INTERP {
                continue;
            }
            let start = header.offset as usize;
            let len = header.filesz as usize;
            let end = start.checked_add(len).ok_or(Error::OffsetOverflow)?;
            if end > bytes.len() || len == 0 {
                return Err(Error::LoadSegmentOutOfRange);
            }
            let raw = &bytes[start..end];
            let raw = match raw.iter().position(|&byte| byte == 0) {
                Some(nul) => &raw[..nul],
                None => raw,
            };
            return core::str::from_utf8(raw)
                .map(Some)
                .map_err(|_| Error::BadInterpreter);
        }

        Ok(None)
    }

    pub fn dynamic_segment(&self, bytes: &[u8]) -> Result<Option<ProgramHeader>, Error> {
        for index in 0..self.phnum as usize {
            let header = self.program_header(bytes, index)?;
            if header.header_type == PT_DYNAMIC {
                return Ok(Some(header));
            }
        }

        Ok(None)
    }

    fn program_table_range(&self, bytes: &[u8]) -> Result<(), Error> {
        let size = self
            .phentsize
            .checked_mul(self.phnum)
            .ok_or(Error::OffsetOverflow)? as u64;
        let end = self.phoff.checked_add(size).ok_or(Error::OffsetOverflow)? as usize;
        if end > bytes.len() {
            return Err(Error::ProgramHeaderOutOfRange);
        }
        Ok(())
    }
}

