#[repr(C)]
#[derive(Clone, Copy)]
pub struct TrapFrame {
    pub regs: [usize; 32],
    pub sepc: usize,
    pub sstatus: usize,
}

impl TrapFrame {
    pub const fn new(entry: usize, stack_pointer: usize) -> Self {
        let mut regs = [0usize; 32];
        regs[2] = stack_pointer;
        Self {
            regs,
            sepc: entry,
            sstatus: USER_SSTATUS,
        }
    }

    pub fn syscall_number(&self) -> usize {
        self.regs[17]
    }

    pub fn syscall_args(&self) -> [usize; 6] {
        [
            self.regs[10],
            self.regs[11],
            self.regs[12],
            self.regs[13],
            self.regs[14],
            self.regs[15],
        ]
    }

    pub fn set_return_value(&mut self, value: isize) {
        self.regs[10] = value as usize;
    }

    pub fn apply_exec(&mut self, entry: usize, stack_pointer: usize) {
        self.regs.fill(0);
        self.regs[2] = stack_pointer;
        self.sepc = entry;
        self.sstatus = USER_SSTATUS;
    }
}

pub fn run_loaded_elf(loaded: LoadedElf, files: FileCatalog, cwd: String, exec_path: String) {
    let entry = loaded.entry;
    let stack_pointer = loaded.stack_pointer;
    let pending = if is_script_runner(&files) {
        let mut pending = pending_script_programs(&files);
        if !pending.is_empty() {
            pending.remove(0);
        }
        pending
    } else if cwd == "/" {
        pending_programs(&files)
    } else {
        Vec::new()
    };
    let mut task = UserTask::from_loaded_elf_with_cwd(loaded, files.clone(), cwd);
    task.set_exec_path(&exec_path);
    let frame = TrapFrame::new(entry, stack_pointer);
    let mut scheduler = Scheduler::new(task, frame, files, pending);

    unsafe {
        SCHEDULER = &mut scheduler;
        write_stvec(__riscv_trap_entry as usize);
        clear_sie(SIE_SEIE);
        crate::arch::set_timer_after_us(TIMER_SLICE_US);
        set_sie(SIE_STIE);
        println!("task: entering RISC-V user mode entry=0x{:x}", entry);
        __riscv_enter_user(&scheduler.tasks[0].frame, scheduler.tasks[0].task.satp());
    }
}

