            let satp = scheduler.handle_syscall(frame);
            if scheduler.is_done() {
                if scheduler.start_next_root(frame) {
                    return scheduler.current_satp();
                } else {
                    let status = scheduler.root_status().unwrap_or(0);
                    println!("task: RISC-V user task complete status={}", status);
                    crate::arch::shutdown();
                }
            }
