    fn read_sector(&mut self, sector: u64, buffer: &mut [u8; SECTOR_SIZE]) -> Result<(), Error>;
    fn capacity_sectors(&self) -> u64;
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum Error {
    NoDevice,
    Timeout,
    UnexpectedUsedId(u32),
    DeviceStatus(u8),
}

impl Error {
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::NoDevice => "no block device",
            Self::Timeout => "timeout",
            Self::UnexpectedUsedId(_) => "unexpected used descriptor id",
            Self::DeviceStatus(_) => "device returned nonzero request status",
        }
    }
}

pub fn smoke_test() {
    #[cfg(target_arch = "riscv64")]
    {
        match virtio_mmio::BlockDevice::probe() {
            Some(mut device) => {
                println!(
                    "block: virtio-mmio found base=0x{:x} transport={} capacity={} sectors",
                    device.mmio_base(),
                    device.transport_name(),
                    device.capacity_sectors()
                );
                let mut sector = [0; SECTOR_SIZE];
                match device.read_sector(0, &mut sector) {
                    Ok(()) => {
                        println!(
                            "block: sector0 {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x}",
                            sector[0],
                            sector[1],
                            sector[2],
                            sector[3],
                            sector[4],
                            sector[5],
                            sector[6],
                            sector[7]
                        );
                    }
                    Err(error) => println!("block: sector0 read failed: {}", error.as_str()),
                }
                match device.read_sector(2, &mut sector) {
                    Ok(()) => {
                        println!(
                            "block: sector2 ext4_magic_candidate={:02x}{:02x}",
                            sector[57], sector[56]
                        );
                    }
                    Err(error) => println!("block: sector2 read failed: {}", error.as_str()),
                }
                crate::fs::ext4::smoke_test(&mut device);
            }
            None => println!("block: no RISC-V virtio-mmio block device found"),
        }
    }

    #[cfg(not(target_arch = "riscv64"))]
    println!("block: smoke skipped on this architecture");
}

