const REG_DRIVER_FEATURES_SEL: usize = 0x024;
const REG_GUEST_PAGE_SIZE: usize = 0x028;
const REG_QUEUE_SEL: usize = 0x030;
const REG_QUEUE_NUM_MAX: usize = 0x034;
const REG_QUEUE_NUM: usize = 0x038;
const REG_QUEUE_ALIGN: usize = 0x03c;
const REG_QUEUE_PFN: usize = 0x040;
const REG_QUEUE_READY: usize = 0x044;
const REG_QUEUE_NOTIFY: usize = 0x050;
const REG_STATUS: usize = 0x070;
const REG_QUEUE_DESC_LOW: usize = 0x080;
const REG_QUEUE_DESC_HIGH: usize = 0x084;
const REG_QUEUE_DRIVER_LOW: usize = 0x090;
const REG_QUEUE_DRIVER_HIGH: usize = 0x094;
const REG_QUEUE_DEVICE_LOW: usize = 0x0a0;
const REG_QUEUE_DEVICE_HIGH: usize = 0x0a4;
const REG_CONFIG: usize = 0x100;

const STATUS_ACKNOWLEDGE: u32 = 1;
const STATUS_DRIVER: u32 = 2;
const STATUS_DRIVER_OK: u32 = 4;
const STATUS_FEATURES_OK: u32 = 8;
const STATUS_FAILED: u32 = 128;

const DESC_F_NEXT: u16 = 1;
const DESC_F_WRITE: u16 = 2;

const QUEUE_SIZE: u16 = 8;
const QUEUE_SIZE_USIZE: usize = QUEUE_SIZE as usize;
const VIRTIO_BLK_T_IN: u32 = 0;
const DESC_AREA_SIZE: usize = size_of::<VirtqDesc>() * QUEUE_SIZE_USIZE;
const AVAIL_AREA_SIZE: usize = size_of::<VirtqAvail>();
const LEGACY_USED_OFFSET: usize = align_up_usize(DESC_AREA_SIZE + AVAIL_AREA_SIZE, PAGE_SIZE);

const MMIO_BASES: [usize; 8] = [
    0x1000_1000,
    0x1000_2000,
    0x1000_3000,
    0x1000_4000,
    0x1000_5000,
    0x1000_6000,
    0x1000_7000,
    0x1000_8000,
];

pub struct BlockDevice {
    base: usize,
    queue_size: u16,
    queue: Box<QueueMemory>,
    last_used_idx: u16,
    capacity_sectors: u64,
    transport: TransportVersion,
}

impl BlockDevice {
    pub fn probe() -> Option<Self> {
        for base in MMIO_BASES {
            if read_reg(base, REG_MAGIC) != VIRTIO_MAGIC {
                continue;
            }
            if read_reg(base, REG_DEVICE_ID) != VIRTIO_DEVICE_BLOCK {
                continue;
            }
            if let Some(device) = unsafe { Self::init(base) } {
                return Some(device);
            }
        }

        None
    }

    pub const fn mmio_base(&self) -> usize {
        self.base
    }

    pub const fn capacity_sectors(&self) -> u64 {
        self.capacity_sectors
    }

    pub const fn transport_name(&self) -> &'static str {
        match self.transport {
            TransportVersion::Legacy => "legacy",
            TransportVersion::Modern => "modern",
        }
    }

    pub fn read_sector(
        &mut self,
        sector: u64,
        buffer: &mut [u8; SECTOR_SIZE],
    ) -> Result<(), Error> {
        self.queue.header.request_type = VIRTIO_BLK_T_IN;
        self.queue.header.reserved = 0;
        self.queue.header.sector = sector;
        self.queue.data = [0; SECTOR_SIZE];
        self.queue.status = 0xff;

        let header_addr = phys_addr(&self.queue.header);
        let data_addr = phys_addr(&self.queue.data);
        let status_addr = phys_addr(&self.queue.status);

        self.queue.desc[0] = VirtqDesc {
            addr: header_addr,
            len: size_of::<VirtioBlkReqHeader>() as u32,
            flags: DESC_F_NEXT,
            next: 1,
        };
        self.queue.desc[1] = VirtqDesc {
            addr: data_addr,
            len: SECTOR_SIZE as u32,
            flags: DESC_F_NEXT | DESC_F_WRITE,
            next: 2,
        };
        self.queue.desc[2] = VirtqDesc {
            addr: status_addr,
            len: 1,
            flags: DESC_F_WRITE,
            next: 0,
        };

        let avail_slot = (self.queue.avail.idx % self.queue_size) as usize;
        self.queue.avail.ring[avail_slot] = 0;
        fence(Ordering::SeqCst);
        unsafe {
            write_volatile(
                &mut self.queue.avail.idx,
                self.queue.avail.idx.wrapping_add(1),
            );
        }
        fence(Ordering::SeqCst);
        write_reg(self.base, REG_QUEUE_NOTIFY, 0);

        self.wait_used()?;

        fence(Ordering::SeqCst);
        let status = unsafe { read_volatile(&self.queue.status) };
        if status != 0 {
            return Err(Error::DeviceStatus(status));
        }

        *buffer = self.queue.data;
        Ok(())
    }

    unsafe fn init(base: usize) -> Option<Self> {
        write_reg(base, REG_STATUS, 0);
        write_reg(base, REG_STATUS, STATUS_ACKNOWLEDGE);
        write_reg(base, REG_STATUS, STATUS_ACKNOWLEDGE | STATUS_DRIVER);
        let mut status = STATUS_ACKNOWLEDGE | STATUS_DRIVER;

        let version = match read_reg(base, REG_VERSION) {
            1 => TransportVersion::Legacy,
            2 => TransportVersion::Modern,
            _ => {
                write_reg(base, REG_STATUS, status | STATUS_FAILED);
                return None;
            }
        };
        let high_features = read_device_features(base, 1);
        let high_driver_features = match version {
            TransportVersion::Legacy => 0,
            TransportVersion::Modern => {
                if high_features & VIRTIO_VERSION_1_HIGH_BIT != 0 {
                    VIRTIO_VERSION_1_HIGH_BIT
                } else {
                    write_reg(base, REG_STATUS, status | STATUS_FAILED);
                    return None;
                }
            }
        };

        write_reg(base, REG_DRIVER_FEATURES_SEL, 0);
        write_reg(base, REG_DRIVER_FEATURES, 0);
        write_reg(base, REG_DRIVER_FEATURES_SEL, 1);
        write_reg(base, REG_DRIVER_FEATURES, high_driver_features);

        status |= STATUS_FEATURES_OK;
        write_reg(base, REG_STATUS, status);
        if read_reg(base, REG_STATUS) & STATUS_FEATURES_OK == 0 {
            write_reg(base, REG_STATUS, status | STATUS_FAILED);
            return None;
        }

        write_reg(base, REG_QUEUE_SEL, 0);
        let max_queue = read_reg(base, REG_QUEUE_NUM_MAX);
        if max_queue < 3 {
            write_reg(base, REG_STATUS, status | STATUS_FAILED);
            return None;
        }

        if version == TransportVersion::Legacy {
            write_reg(base, REG_GUEST_PAGE_SIZE, PAGE_SIZE as u32);
        }

        let queue_size = QUEUE_SIZE.min(max_queue as u16);
        let mut queue = Box::new(QueueMemory::new());
        write_reg(base, REG_QUEUE_NUM, queue_size as u32);

        match version {
            TransportVersion::Legacy => {
                let desc_addr = phys_addr(&queue.desc);
                if desc_addr as usize % PAGE_SIZE != 0 {
                    write_reg(base, REG_STATUS, status | STATUS_FAILED);
                    return None;
                }
                write_reg(base, REG_QUEUE_ALIGN, PAGE_SIZE as u32);
                write_reg(base, REG_QUEUE_PFN, (desc_addr as usize / PAGE_SIZE) as u32);
            }
            TransportVersion::Modern => {
                write_addr(
                    base,
                    REG_QUEUE_DESC_LOW,
                    REG_QUEUE_DESC_HIGH,
                    phys_addr(&queue.desc),
                );
                write_addr(
                    base,
                    REG_QUEUE_DRIVER_LOW,
                    REG_QUEUE_DRIVER_HIGH,
                    phys_addr(&queue.avail),
                );
                write_addr(
                    base,
                    REG_QUEUE_DEVICE_LOW,
                    REG_QUEUE_DEVICE_HIGH,
                    phys_addr(&queue.used),
                );
                write_reg(base, REG_QUEUE_READY, 1);
            }
        }

