    kind: usize,
    protocol: usize,
    fd_refs: usize,
    local_port: Option<u16>,
    peer_port: Option<u16>,
    packet_ifindex: i32,
    pending_connect_port: Option<u16>,
    listening: bool,
    pending_connections: Vec<PendingStreamConnection>,
    datagrams: Vec<Datagram>,
    stream: Option<StreamEndpoint>,
    peer_cred: Option<SocketPeerCred>,
    multicast_group_joined: bool,
    unix_name: Option<[u8; 16]>,
    attached_bpf_fd: Option<usize>,
    pending_bpf_fd: Option<usize>,
    netlink_deleted_addr_ifindices: Vec<u32>,
}

impl SocketState {
    fn new(domain: usize, kind: usize, protocol: usize) -> Self {
        Self {
            domain,
            kind,
            protocol,
            fd_refs: 0,
            local_port: None,
            peer_port: None,
            packet_ifindex: 0,
            pending_connect_port: None,
            listening: false,
            pending_connections: Vec::new(),
            datagrams: Vec::new(),
            stream: None,
            peer_cred: None,
            multicast_group_joined: false,
            unix_name: None,
            attached_bpf_fd: None,
            pending_bpf_fd: None,
            netlink_deleted_addr_ifindices: Vec::new(),
        }
    }

    fn open_fd(&mut self) {
        if let Some(stream) = self.stream.as_ref() {
            stream.open();
        }
        self.fd_refs = self.fd_refs.saturating_add(1);
    }

    fn close_fd(&mut self) {
        if self.fd_refs == 0 {
            return;
        }
        if let Some(stream) = self.stream.as_ref() {
            stream.close();
        }
        self.fd_refs = self.fd_refs.saturating_sub(1);
        if self.fd_refs == 0 && !(socket_kind_is_stream_like(self.kind) && self.listening) {
            for connection in self.pending_connections.drain(..) {
                connection.stream.close();
            }
        }
    }

    fn attach_stream(&mut self, stream: StreamEndpoint) {
        for _ in 0..self.fd_refs {
            stream.open();
        }
        self.stream = Some(stream);
    }

    fn readable_now(&self) -> bool {
        !self.datagrams.is_empty()
            || !self.pending_connections.is_empty()
            || self
                .stream
                .as_ref()
                .map(StreamEndpoint::readable_now)
                .unwrap_or(false)
    }

    fn read_half_closed(&self) -> bool {
        socket_kind_is_stream_like(self.kind)
            && self
                .stream
                .as_ref()
                .map(StreamEndpoint::read_half_closed)
                .unwrap_or(false)
    }

    fn datagram_queued_bytes(&self) -> usize {
        self.datagrams
            .iter()
            .map(|datagram| datagram.bytes.len())
            .sum()
    }

    fn datagram_queue_has_space_for(&self, len: usize) -> bool {
        self.datagram_queued_bytes().saturating_add(len) <= SOCKET_BUFFER_SIZE
    }
}

