fn read_netlink_socket(
    socket: &Rc<RefCell<SocketState>>,
    output: &mut [u8],
) -> Result<usize, FdError> {
    let mut socket = socket.borrow_mut();
    if socket.domain != AF_NETLINK {
        return Err(FdError::BadFd);
    }
    let Some(datagram) = socket.datagrams.first().cloned() else {
        return Err(FdError::WouldBlock);
    };
    socket.datagrams.remove(0);
    let len = output.len().min(datagram.bytes.len());
    output[..len].copy_from_slice(&datagram.bytes[..len]);
    Ok(len)
}

fn write_netlink_socket(
    socket: &Rc<RefCell<SocketState>>,
    input: &[u8],
) -> Result<usize, FdError> {
    let mut socket = socket.borrow_mut();
    if socket.domain != AF_NETLINK {
        return Err(FdError::BadFd);
    }
    let bytes = netlink_response_for_request(input, &mut socket);
    if !bytes.is_empty() {
        socket.datagrams.push(Datagram {
            source: sockaddr_netlink(0),
            bytes,
        });
    }
    Ok(input.len())
}

