fn read_relative_timeout_deadline(&self, timeout_ptr: usize) -> Result<Option<u64>, isize> {
    if timeout_ptr == 0 {
        return Ok(None);
    }
    let mut raw = [0u8; 16];
    if let Err(error) = self.aspace.read(timeout_ptr, &mut raw) {
        println!("futex: copy timeout failed: {}", error.as_str());
        return Err(-14);
    }
    let secs = read_u64(&raw, 0);
    let nsecs = read_u64(&raw, 8);
    if nsecs >= 1_000_000_000 {
        return Err(-22);
    }
    let delta_us = secs
        .saturating_mul(1_000_000)
        .saturating_add(nsecs.saturating_add(999) / 1_000);
    Ok(Some(
        crate::arch::monotonic_time_us().saturating_add(delta_us),
    ))
}

