    self.read_file_inode_prefix(device, inode, max_len)
}

pub fn read_whole_file_by_path(
    &self,
    device: &mut impl BlockDevice,
    path: &str,
    max_len: usize,
) -> Result<(FileMetadata, Vec<u8>), Error> {
    let inode_no = self.lookup_path(device, path)?;
    let inode = self.read_inode(device, inode_no)?;
    let metadata = inode.metadata(inode_no);
    let bytes = self.read_file_inode_prefix(device, inode, max_len)?;
    Ok((metadata, bytes))
}

pub fn metadata_by_path(
    &self,
    device: &mut impl BlockDevice,
    path: &str,
) -> Result<FileMetadata, Error> {
    let inode_no = self.lookup_path(device, path)?;
    let inode = self.read_inode(device, inode_no)?;
    Ok(inode.metadata(inode_no))
}

pub fn read_dir_by_path(
    &self,
    device: &mut impl BlockDevice,
    path: &str,
) -> Result<(FileMetadata, Vec<OwnedDirectoryEntry>), Error> {
    let inode_no = self.lookup_path(device, path)?;
    let inode = self.read_inode(device, inode_no)?;
    let metadata = inode.metadata(inode_no);
    let mut entries = Vec::new();

    self.visit_dir_entries(device, inode, |entry| {
        entries.push(OwnedDirectoryEntry {
            inode: entry.inode as u64,
            name: alloc::string::String::from(entry.name),
            file_type: match entry.file_type {
                2 => FileType::Directory,
                7 => FileType::Symlink,
                _ => FileType::Regular,
            },
        });
        Ok(())
    })?;

    Ok((metadata, entries))
}

fn lookup_path(&self, device: &mut impl BlockDevice, path: &str) -> Result<u32, Error> {
    if path == "/" || path.is_empty() {
        return Ok(ROOT_INODE);
    }

    let mut current = ROOT_INODE;
    for component in path.trim_start_matches('/').split('/') {
        if component.is_empty() {
            continue;
        }
        current = self.lookup_child(device, current, component)?;
    }

    Ok(current)
}

