fn map_kernel_identity(&mut self) -> Result<(), Error> {
    const UART_BASE: usize = 0x1000_0000;
    const VIRTIO_BASE: usize = 0x1000_1000;
    const VIRTIO_END: usize = 0x1000_9000;
    const CLINT_BASE: usize = 0x0200_0000;
    const CLINT_END: usize = 0x0201_0000;
    const PLIC_BASE: usize = 0x0c00_0000;
    const PLIC_END: usize = 0x1000_0000;

    self.map_identity_large_range(
        crate::arch::PHYS_MEMORY_BASE,
        crate::arch::PHYS_MEMORY_BASE + crate::arch::PHYS_MEMORY_SIZE,
        MapFlags::kernel_read_write().union(MapFlags::EXECUTE),
    )?;
    self.map_identity_range(
        UART_BASE,
        UART_BASE + PAGE_SIZE,
        MapFlags::kernel_read_write(),
    )?;
    self.map_identity_range(VIRTIO_BASE, VIRTIO_END, MapFlags::kernel_read_write())?;
    self.map_identity_range(CLINT_BASE, CLINT_END, MapFlags::kernel_read_write())?;
    self.map_identity_range(PLIC_BASE, PLIC_END, MapFlags::kernel_read_write())?;
    Ok(())
}

