fn map_load_plan(
    &mut self,
    bytes: &[u8],
    plan: LoadPlan,
    load_bias: usize,
) -> Result<(), Error> {
    for segment in plan.segments() {
        let flags = segment_flags(segment.flags());
        let start = add_load_bias(segment.map_start() as usize, load_bias)?;
        let end = add_load_bias(segment.map_end() as usize, load_bias)?;
        self.map_range(start, end, flags)?;

        let file_start = segment.offset() as usize;
        let file_end = file_start
            .checked_add(segment.filesz() as usize)
            .ok_or(Error::AddressOverflow)?;
        if file_end > bytes.len() {
            return Err(Error::SegmentOutOfRange);
        }
        let write_addr = add_load_bias(segment.vaddr() as usize, load_bias)?;
        self.write(write_addr, &bytes[file_start..file_end])?;

        // Freshly allocated frames are zeroed before mapping, so the BSS tail is
        // already zero. Read one byte from the end when present to verify mapping.
        if segment.memsz() > segment.filesz() {
            let bss_start = add_load_bias(
                segment
                    .vaddr()
                    .checked_add(segment.filesz())
                    .ok_or(Error::AddressOverflow)? as usize,
                load_bias,
            )?;
            let mut byte = [0u8; 1];
            self.read(bss_start, &mut byte)?;
            if byte[0] != 0 {
                return Err(Error::BssNotZero);
            }
        }
    }
    Ok(())
}

