fn map_signal_trampoline(&mut self) -> Result<(), Error> {
    const TRAMPOLINE: [u8; 8] = [
        0x93, 0x08, 0xb0, 0x08, // li a7, 139
        0x73, 0x00, 0x00, 0x00, // ecall
    ];

    let frame = frame::alloc().ok_or(Error::OutOfFrames)?;
    zero_frame(frame);
    if let Err(error) = self.map_frame(
        SIGNAL_TRAMPOLINE,
        frame,
        MapFlags::READ
            .union(MapFlags::EXECUTE)
            .union(MapFlags::USER),
    ) {
        frame::dealloc(frame);
        return Err(error);
    }
    self.write(SIGNAL_TRAMPOLINE, &TRAMPOLINE)
}

