fn map_initial_stack(&mut self, stack: InitialStack<'_>) -> Result<usize, Error> {
    let stack_bottom = USER_STACK_TOP - USER_STACK_SIZE;
    self.reserve_anonymous_with_flags(
        stack_bottom,
        USER_STACK_SIZE,
        MapFlags::READ.union(MapFlags::WRITE).union(MapFlags::USER),
    )?;

    let mut builder = StackBuilder::new(USER_STACK_TOP);
    let mut argv_ptrs = Vec::new();
    for arg in stack.argv {
        argv_ptrs.push(builder.push_bytes_with_nul(arg.as_bytes())?);
    }

    let mut env_ptrs = Vec::new();
    for env in stack.env {
        env_ptrs.push(builder.push_bytes_with_nul(env.as_bytes())?);
    }
    let random_ptr = builder.push_bytes(&[
        0x41, 0x54, 0x5f, 0x52, 0x41, 0x4e, 0x44, 0x4f, 0x4d, 0x5f, 0x4f, 0x53, 0x42, 0x4f,
        0x59, 0x21,
    ])?;
    builder.align_down(16);

    let mut aux_pairs = if stack.phdr != 0 { 7 } else { 6 };
    if stack.at_base != 0 {
        aux_pairs += 1;
    }
    let pointer_words = 1 + stack.argv.len() + 1 + stack.env.len() + 1 + aux_pairs * 2;
    if pointer_words % 2 != 0 {
        builder.push_usize(0)?;
