    builder.push_aux(0, 0)?;
    builder.push_aux(25, random_ptr)?;
    if stack.at_base != 0 {
        builder.push_aux(7, stack.at_base)?;
    }
    builder.push_aux(9, stack.main_entry)?;
    builder.push_aux(5, stack.phnum)?;
    builder.push_aux(4, stack.phent)?;
    if stack.phdr != 0 {
        builder.push_aux(3, stack.phdr)?;
    }
    builder.push_aux(6, PAGE_SIZE)?;

    builder.push_usize(0)?;

