fn map_identity_range(
    &mut self,
    start: usize,
    end: usize,
    flags: MapFlags,
) -> Result<(), Error> {
    let mut current = align_down(start, PAGE_SIZE);
    let end = align_up(end, PAGE_SIZE);
    while current < end {
        self.inner
            .borrow_mut()
            .page_table
            .map(current, current, flags)
            .map_err(Error::PageTable)?;
        current = current
            .checked_add(PAGE_SIZE)
            .ok_or(Error::AddressOverflow)?;
    }
    Ok(())
}

